"use strict";
var http=require("http"),os=require("os"),cp=require("child_process"),Buffer=require("buffer").Buffer;
var A={
  "index.html":"",
  "extrator.html":"",
  "manifest.json":"",
  "sw.js":"",
  "favicon.svg":"",
  "icon-192.png":"",
  "icon-512.png":"",
  "opengraph.jpg":"",
  "assets/app.js":"",
};

var M={".html":"text/html; charset=utf-8",".js":"application/javascript; charset=utf-8",
".css":"text/css; charset=utf-8",".json":"application/json",".svg":"image/svg+xml",
".png":"image/png",".jpg":"image/jpeg",".jpeg":"image/jpeg"};
var PORT=18633;
function ext(k){var i=k.lastIndexOf(".");return i>-1?k.slice(i):""}
var srv=http.createServer(function(req,res){
  var k=(req.url||"/").split("?")[0].replace(/^\//,"")||"index.html";
  var b=A[k]||A["index.html"];
  var data=Buffer.from(b,"base64");
  res.writeHead(200,{"Content-Type":M[ext(k)]||"application/octet-stream","Cache-Control":"no-store","Content-Length":data.length});
  res.end(data);
});
srv.on("error",function(e){
  console.log(e.code==="EADDRINUSE"?"\n  ERRO: porta "+PORT+" em uso. Feche a outra janela.\n":"\n  ERRO: "+e.message+"\n");
  process.exit(1);
});
srv.listen(PORT,"127.0.0.1",function(){
  var url="http://127.0.0.1:"+PORT;
  console.log("\n  SK Code Editor Desktop rodando em: "+url);
  console.log("  Mantenha esta janela aberta. Ctrl+C para fechar.\n");
  var p=os.platform();
  cp.exec(p==="win32"?'start "" "'+url+'"':p==="darwin"?'open "'+url+'"':'xdg-open "'+url+'"');
});
